const TRAIL_DATA={"framework":"openclaw","trailName":"The Gateway Trail","stops":[{"name":"Channel Outpost","subtitle":"Message Arrives","concept":"Channel Plugins","landmarkType":"town","code":{"file":"extensions/whatsapp/src/plugin.ts","content":"// extensions/whatsapp/src/plugin.ts (conceptual)
import { ChannelPlugin } from '@openclaw/types'

export const whatsappPlugin: ChannelPlugin = {
  config: {
    listAccountIds(cfg) {
      return cfg.whatsapp?.accounts?.map(a => a.id) ?? []
    },
    async isConfigured(account) {
      return !!account.phoneNumber
    },
    resolveAccount(cfg, id) {
      return cfg.whatsapp.accounts.find(a => a.id === id)
    },
  },
  gateway: {
    async startAccount({ account, gateway }) {
      const sock = makeWASocket({ auth: account.auth })
      sock.ev.on('messages.upsert', async ({ messages }) => {
        for (const msg of messages) {
          await gateway.handleInbound({
            channel: 'whatsapp',
            peer: msg.key.remoteJid,
            text: msg.message?.conversation,
            accountId: account.id,
          })
        }
      })
    },
    async stopAccount({ account }) {
      // Graceful disconnect
    },
  },
}","language":"typescript"},"narration":"Every journey starts at a channel outpost. OpenClaw connects to thirteen different messaging platforms. Each has a channel plugin following the same interface. Here's the WhatsApp plugin using Baileys to listen for messages. When a message arrives, it normalizes it into a common format and hands it to the gateway."},{"name":"Normalization Pass","subtitle":"Common Message Format","concept":"Channel Plugins","landmarkType":"camp","code":{"file":"src/channels/plugins/types.ts","content":"// src/channels/plugins/types.ts (simplified)
export interface ChannelPlugin {
  config: {
    listAccountIds(cfg: Config): string[]
    isConfigured(account: AccountConfig): Promise<boolean>
    resolveAccount(cfg: Config, id: string): AccountConfig
  }
  gateway?: {
    startAccount(opts: StartAccountOpts): Promise<void>
    stopAccount(opts: StopAccountOpts): Promise<void>
  }
}

// The normalized inbound message shape:
interface InboundMessage {
  channel: string
  accountId: string
  peer: RoutePeer
  text: string
  threadId?: string
  attachments?: Media[]
  guildId?: string
}","language":"typescript"},"narration":"At the Normalization Pass, chaos becomes order. Every messaging platform has its own format. The ChannelPlugin interface forces them all into one shape. The gateway never needs to know whether you messaged from WhatsApp or Telegram."},{"name":"Route Resolution Fork","subtitle":"Finding the Right Agent","concept":"Route Resolution","landmarkType":"mountain","code":{"file":"src/routing/resolve-route.ts","content":"// src/routing/resolve-route.ts (simplified)
export function resolveAgentRoute({
  cfg, channel, accountId, peer, guildId, teamId,
}: ResolveRouteInput): ResolvedRoute {

  for (const agent of cfg.agents.list) {
    const routing = agent.routing

    // 1. Exact peer match (highest priority)
    const peerMatch = routing.peer?.find(
      b => b.peer === peer.id && b.channel === channel
    )
    if (peerMatch) return { agentId: agent.id, matchedBy: 'peer' }

    // 2. Guild/server match
    const guildMatch = routing.guild?.find(
      b => b.guildId === guildId && b.channel === channel
    )
    if (guildMatch) return { agentId: agent.id, matchedBy: 'guild' }

    // 3. Account-level match
    const accountMatch = routing.account?.find(
      b => b.accountId === accountId && b.channel === channel
    )
    if (accountMatch) return { agentId: agent.id, matchedBy: 'account' }
  }

  return { agentId: cfg.agents.default, matchedBy: 'default' }
}","language":"typescript"},"narration":"Here's where the trail forks. The resolver checks priority order: specific peer binding, then guild/server, then account, then default. One gateway can serve different agents to different people."},{"name":"Session Persistence Camp","subtitle":"Loading Conversation State","concept":"Session Persistence","landmarkType":"camp","code":{"file":"src/sessions/session-utils.ts","content":"// src/sessions/session-utils.ts (simplified)
import { readFile, writeFile, mkdir } from 'fs/promises'

const SESSIONS_DIR = '~/.openclaw/sessions'

export async function loadSessionEntry(
  agentId: string,
  sessionKey: string,
): Promise<SessionEntry> {
  const path = `${SESSIONS_DIR}/${agentId}/${sessionKey}.json`

  try {
    const raw = await readFile(path, 'utf-8')
    return JSON.parse(raw)
  } catch {
    return {
      sessionKey,
      agentId,
      transcript: [],
      metadata: {
        model: 'anthropic/claude-opus-4-6',
        thinkingLevel: 'medium',
        tokensUsed: 0,
        createdAt: Date.now(),
      },
    }
  }
}","language":"typescript"},"narration":"Sessions are just JSON files on disk. Each agent-plus-peer combination gets its own file. If the file doesn't exist, a fresh session starts with sensible defaults. Zero database dependencies, easy backup."},{"name":"Gateway Control Ridge","subtitle":"The WebSocket Command Center","concept":"Gateway Control Plane","landmarkType":"mountain","code":{"file":"src/gateway/server-chat.ts","content":"// src/gateway/server-chat.ts (simplified)
export function createChatRunRegistry(gateway: GatewayServer) {

  async function handleChatSend(
    sessionEntry: SessionEntry,
    message: InboundMessage,
  ) {
    sessionEntry.transcript.push({
      role: 'user',
      content: message.text,
      timestamp: Date.now(),
    })

    const agentRpc = gateway.acp.getClient(sessionEntry.agentId)
    const stream = await agentRpc.call('chat.send', {
      sessionId: sessionEntry.sessionKey,
      messages: sessionEntry.transcript,
      tools: sessionEntry.metadata.enabledTools,
      model: sessionEntry.metadata.model,
    })

    for await (const chunk of stream) {
      if (chunk.type === 'text') {
        gateway.broadcast('chat.stream', { text: chunk.text })
      } else if (chunk.type === 'tool_use') {
        const result = await executeTool(chunk.tool, chunk.input)
        agentRpc.sendToolResult(chunk.id, result)
      }
    }
    await saveSession(sessionEntry)
  }

  return { handleChatSend }
}","language":"typescript"},"narration":"The gateway server accepts WebSocket connections from channels, the CLI, and native apps. The streaming loop handles text and tool calls differently. Text streams in real time; tool calls get executed on the gateway and results feed back."},{"name":"Agent RPC Rapids","subtitle":"Talking to the AI","concept":"Gateway Control Plane","landmarkType":"river","code":{"file":"src/acp/client.ts","content":"// src/acp/client.ts (simplified)
export function createAcpClient(agentId: string, wsUrl: string) {
  const ws = new WebSocket(wsUrl)

  async function* call(
    method: string,
    params: ChatSendParams,
  ): AsyncGenerator<AgentChunk> {
    const requestId = crypto.randomUUID()

    ws.send(JSON.stringify({
      jsonrpc: '2.0',
      id: requestId,
      method,
      params,
    }))

    while (true) {
      const msg = await nextMessage(ws, requestId)
      if (msg.type === 'done') break
      yield msg
    }
  }

  function sendToolResult(toolCallId: string, result: ToolResult) {
    ws.send(JSON.stringify({
      jsonrpc: '2.0',
      method: 'tool.result',
      params: { toolCallId, result },
    }))
  }

  return { call, sendToolResult }
}","language":"typescript"},"narration":"Now we cross the RPC Rapids. The gateway and agent communicate over JSON-RPC. The agent decides what to do, but the gateway controls what actually happens on your machine. Security through architecture."},{"name":"Tool Execution Gorge","subtitle":"Running Commands on the Host","concept":"Gateway Control Plane","landmarkType":"forest","code":{"file":"src/agents/bash-tools.exec.ts","content":"// src/agents/bash-tools.exec.ts (simplified)
export async function executeBashTool(
  input: { command: string },
  context: ToolContext,
): Promise<ToolResult> {
  const { command } = input
  const { sessionEntry, securityPolicy } = context

  if (!securityPolicy.allowBash) {
    return { error: 'Bash execution not permitted' }
  }

  const pty = spawn('bash', ['-c', command], {
    cwd: sessionEntry.metadata.workingDir,
    env: { ...process.env, ...sessionEntry.metadata.env },
    timeout: 120_000,
  })

  let stdout = ''
  pty.onData(data => { stdout += data })
  const exitCode = await pty.wait()

  return {
    stdout: stdout.slice(0, 100_000),
    exitCode,
  }
}","language":"typescript"},"narration":"Deep in Tool Execution Gorge, the agent's intentions become real actions. Security check first, then a real PTY with a two-minute timeout. Bash is just one tool — same pattern for browser control, canvas, and device actions."},{"name":"Response Delivery Frontier","subtitle":"Back Through the Channel","concept":"Channel Plugins","landmarkType":"town","code":{"file":"src/gateway/server-channels.ts","content":"// src/gateway/server-channels.ts (simplified)
export function createChannelManager(gateway: GatewayServer) {

  async function deliverResponse(
    sessionEntry: SessionEntry,
    response: AgentResponse,
  ) {
    const { channel, peer, accountId } = sessionEntry.routing
    const plugin = gateway.channels.get(channel)

    const formatted = formatForChannel(channel, response.text, {
      maxLength: getChannelLimit(channel),
    })

    for (const chunk of formatted) {
      await plugin.send({ accountId, peer, text: chunk })
    }

    sessionEntry.transcript.push({
      role: 'assistant',
      content: response.text,
      timestamp: Date.now(),
    })
    await saveSession(sessionEntry)

    gateway.broadcast('chat.response', { text: response.text })
