836→  const skyColors = getSkyColors();
837→
838→  // Sky gradient (banded for EGA feel)
839→  const bands = 10;
840→  const skyBottom = 110;
841→  for (let i = 0; i < bands; i++) {
842→    const t = i / (bands - 1);
843→    const r1 = parseInt(skyColors.top.substr(1, 2), 16);
844→    const g1 = parseInt(skyColors.top.substr(3, 2), 16);
845→    const b1 = parseInt(skyColors.top.substr(5, 2), 16);
846→    const r2 = parseInt(skyColors.bottom.substr(1, 2), 16);
847→    const g2 = parseInt(skyColors.bottom.substr(3, 2), 16);
848→    const b2 = parseInt(skyColors.bottom.substr(5, 2), 16);
849→    const r = Math.floor(r1 + (r2 - r1) * t);
850→    const g = Math.floor(g1 + (g2 - g1) * t);
851→    const b = Math.floor(b1 + (b2 - b1) * t);
852→    ctx.fillStyle = `rgb(${r},${g},${b})`;
