  if (correct) {
    var bonus = streak >= 3 ? ' (+5 streak bonus!)' : '';
    resultHtml = '<div style="color:#55FF55; margin-top:8px; font-size:14px;">CORRECT! +10 Health' + bonus + '</div>';
